export async function incrementCounter() {
  const { items } = await db.list('counters', { limit: 1 });
  if (items.length === 0) {
    const [id] = await db.add('counters', [{ value: 1 }]);
    if (!id) throw new Error('Failed to create counter');
    return { id, value: 1 };
  }
  const current = items[0];
  const nextValue = (current.value ?? 0) + 1;
  const [updated] = await db.update('counters', [{ id: current.id, record: { value: nextValue } }]);
  if (!updated) throw new Error('Failed to update counter');
  return { id: current.id, value: nextValue };
}"},{"title":"Simple CRUD list","code":"import { db } from '@appdeploy/sdk';

export async function addItem(text) {
  const [id] = await db.add('todos', [{ text, done: false }]);
  if (!id) throw new Error('Failed to add item');
  return id;
}

export async function listItems() {
  const { items } = await db.list('todos', { limit: 50 });
  return items;
}

export async function updateItem(id, updates) {
  const [current] = await db.get('todos', [id]);
  if (!current) throw new Error('Item not found');
  const [ok] = await db.update('todos', [{ id, record: { ...current, ...updates } }]);
  if (!ok) throw new Error('Failed to update item');
}

export async function deleteItem(id) {
  const [ok] = await db.delete('todos', [id]);
  if (!ok) throw new Error('Failed to delete item');
}"},{"title":"File upload + URL","code":"import { storage } from '@appdeploy/sdk';

