export async function classifyCatDog(imageBase64, mimeType) {
  try {
    const result = await ai.classify({
      prompt: 'Classify this image as either cat or dog. Choose the most accurate label.',
      labels: ['cat', 'dog'],
      images: [{ data: imageBase64, mimeType }],
      maxRetries: 1
    });
    return { label: result.label, raw: result.text, attempts: result.attempts };
  } catch (error) {
    if (isAppDeployRpcError(error)) {
      throw new Error('AI classify failed (' + error.statusCode + '): ' + (error.responseText || ''));
    }
    throw error;
  }
}"},{"title":"Structured AI extraction","code":"import { ai } from '@appdeploy/sdk';

export async function readMileageFromImage(imageBase64, mimeType) {
  const result = await ai.extract({
    prompt: 'Read the odometer value from this image and return structured data.',
    images: [{ data: imageBase64, mimeType }],
    schema: {
      type: 'object',
      properties: {
        mileage: { type: 'number' },
        confidence: { type: 'number' }
      },
      required: ['mileage']
    },
    temperature: 0.2
  });

  return result.data;
}"},{"title":"Scrape + extract pipeline","code":"import { ai } from '@appdeploy/sdk';

export async function extractProducts(url) {
  const scraped = await ai.scrape({ url });
  if (scraped.status >= 400) {
    throw new Error('Failed to scrape URL');
  }

  const result = await ai.extract({
    content: scraped.text,
    prompt: 'Extract all product listings with name, price, and URL.',
    schema: {
      type: 'object',
      properties: {
        products: {
          type: 'array',
          items: {
            type: 'object',
            properties: { name: { type: 'string' }, price: { type: 'number' }, url: { type: 'string' } },
            required: ['name', 'price']
          }
        }
      },
      required: ['products']
    }
  });

  return result.data;
}"},{"title":"OCR from image","code":"import { ai } from '@appdeploy/sdk';

export async function readReceiptText(imageBase64, mimeType) {
  const result = await ai.ocr({
    images: [{ data: imageBase64, mimeType }],
    prompt: 'Read all visible receipt text. Preserve line breaks.'
  });

  return { text: result.text, attempts: result.attempts };
