export async function summarizeUrl(url) {
  const scraped = await ai.scrape({ url });
  if (scraped.status >= 400) {
    throw new Error('Failed to scrape URL');
  }

  const summary = await ai.generate({
    prompt: `Summarize this page in 5 bullets:\n\n${scraped.text}`
  });

  return summary.text;
}"},{"title":"AI tool loop with ai.run","code":"import { ai, db } from '@appdeploy/sdk';

export async function buildWeeklyPlan(userId) {
  const result = await ai.run({
    prompt: 'Build a 7-day exercise plan from recent workouts',
    tools: [
      {
        name: 'getWorkouts',
        description: 'Fetch recent workouts for user',
        parameters: {
          type: 'object',
          properties: { days: { type: 'number' } },
          required: ['days']
        }
      },
      {
        name: 'emit_result',
        description: 'Return final structured output and finish the agent loop',
        parameters: {
          type: 'object',
          properties: {
            summary: { type: 'string' },
            plan: {
              type: 'array',
              items: { type: 'string' }
            }
          },
          required: ['summary', 'plan']
        }
      }
    ],
    onToolCall: async (name, args) => {
      if (name !== 'getWorkouts') return { error: 'unknown tool' };
      const { items } = await db.list('workouts', { filter: { userId } });
      return items.slice(0, args.days || 30);
    },
    maxSteps: 5
  });

  return result.data || { summary: result.text, plan: [] };
}"},{"title":"Typed database access","code":"import { db } from '@appdeploy/sdk';

