import { randomUUID } from 'crypto';

export async function createGame(creatorName) {
  const playerId = randomUUID();
  const [gameId] = await db.add('games', [{
    players: [{ id: playerId, name: creatorName }],
    status: 'waiting',
  }]);
  if (!gameId) throw new Error('Failed to create game');
  // Return ids; the client must reuse them for future calls.
  return { gameId, playerId };
}

export async function joinGame(gameId, playerId, name) {
  const resolvedPlayerId = playerId || randomUUID();
  const [game] = await db.get('games', [gameId]);
  if (!game) throw new Error('Game not found');

  const alreadyJoined = (game.players || []).some(p => p.id === resolvedPlayerId);
  if (alreadyJoined) return { ok: true };

  const nextPlayers = [...(game.players || []), { id: resolvedPlayerId, name }];
  const [ok] = await db.update('games', [{ id: gameId, record: { ...game, players: nextPlayers } }]);
  if (!ok) throw new Error('Failed to join');
  return { ok: true, playerId: resolvedPlayerId };
}"},{"title":"Multiplayer invite code","code":"import { db } from '@appdeploy/sdk';

export async function createGame(creatorName) {
  const inviteCode = Math.random().toString(36).substring(2, 8).toUpperCase();
  const [gameId] = await db.add('games', [{
    inviteCode,
    players: [{ name: creatorName }],
    status: 'waiting',
  }]);
  if (!gameId) throw new Error('Failed to create game');
  return { gameId, inviteCode };
}

// IMPORTANT: Do NOT use limit with filter ÔÇö filters apply after limit
export async function joinByInviteCode(inviteCode, playerName) {
  const { items } = await db.list('games', {
    filter: { inviteCode: inviteCode.toUpperCase() },
  });
  if (!items.length) throw new Error('Game not found');

  const game = items[0];
  const [ok] = await db.update('games', [{
    id: game.id,
    record: { ...game, players: [...game.players, { name: playerName }] }
  }]);
  if (!ok) throw new Error('Failed to join');
  return { gameId: game.id };
}"},{"title":"Protected endpoint with auth","code":"import { db } from '@appdeploy/sdk';

